const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
};

const quoteResult = (premium: number) => ({ results: [{ premium }] });

const firstInsuranceSurcharge = (base: number): number =>
  Math.ceil(base * FIRST_INSURANCE_SURCHARGE_RATE);

const itemPremium = (item: { type: string }): number => {
  const base = BASE_PREMIUMS[item.type];
  return base + firstInsuranceSurcharge(base);
};

export const runScenario = (input: any): unknown => {
  const items = input.steps[0].items;
  const itemsTotal = items.reduce(
    (sum: number, item: { type: string }) => sum + itemPremium(item),
    0,
  );
  return quoteResult(itemsTotal + PROCESSING_FEE);
};
